{
  "comments": [
    {
      "index": 1,
      "type": "comment",
      "persona": "처음 방문 전 체크하는 사람",
      "intent": "원고에 언급된 배방역에서의 이동 시간을 구체적으로 확인",
      "content": "배방역에서 차로 10~15분이면 도착한다고 하셨는데, 혹시 택시는 자주 잡히는 편인가요?"
    },
    {
      "index": 2,
      "type": "comment",
      "persona": "가족/반려동물 동행을 생각하는 사람",
      "intent": "아이 동반 시 유아 시설이 궁금해 질문",
      "content": "아이 의자나 수유실은 카페마다 다르다고 하셨는데, 대형 베이커리 카페 쪽에는 대부분 갖춰져 있는지 궁금하네요."
    },
    {
      "index": 3,
      "type": "comment",
      "persona": "숫자/조건을 확인하는 사람",
      "intent": "브런치 예산을 구체적으로 확인",
      "content": "1인 브런치 예산이 1만 5천에서 2만 5천원 선이고 음료까지 포함하면 2만 원 후반이라니 참고하겠습니다."
    },
    {
      "index": 4,
      "type": "comment",
      "persona": "주말 혼잡이나 대기 시간을 걱정하는 사람",
      "intent": "주말 붐비는 시간대와 대기 가능성을 경계",
      "content": "주말 정오부터 노을까지가 제일 붐빈다고 하니, 저는 오후 3시 이후로 가는 게 낫겠네요."
    },
    {
      "index": 5,
      "type": "comment",
      "persona": "실제 다녀온 경험을 떠올리는 사람",
      "intent": "일반화된 형태로 테라스 좌석 경험을 회고",
      "content": "테라스 자리가 봄가을에 인기라는데, 바람 부는 날엔 담요를 빌려주는 곳도 있다고 하니 그 점이 괜찮아 보이더라고요."
    },
    {
      "index": 6,
      "type": "comment",
      "persona": "사진보다 편의성을 보는 사람",
      "intent": "콘센트 위치와 자리 선점의 중요성에 주목",
      "content": "콘센트가 붙은 창가 자리가 더 빨리 나간다는 점이 실제로 작업하러 갈 때 큰 차이를 만들 것 같습니다."
    },
    {
      "index": 7,
      "type": "comment",
      "persona": "저장하고 나중에 보려는 사람",
      "intent": "벚꽃 시즌 정보를 메모",
      "content": "벚꽃 절정이 4월 초중순 1~2주라는 정보 저장해둡니다. 그때 맞춰서 한번 가보고 싶네요."
    },
    {
      "index": 8,
      "type": "comment",
      "persona": "살짝 조심스럽게 다른 기준을 덧붙이는 사람",
      "intent": "갓 구운 빵을 노리는 사람에게 오전 방문을 권하는 논리에 이견 제시",
      "content": "오전에 갓 구운 빵이 좋다는 건 알겠는데, 인기 빵이 오후 2~3시면 동난다면 결국 빠른 시간에 가는 게 답이긴 하네요."
    }
  ]
}
